module bin_to_gray_6bit(
    input [5:0] _inv_bin,
    output reg [5:0] gray
);

always @(*) begin
    gray[5] = _inv_bin[5];
    gray[4] = _inv_bin[5] ^ _inv_bin[4];
    gray[3] = _inv_bin[4] ^ _inv_bin[3];
    gray[2] = _inv_bin[3] ^ _inv_bin[2];
    gray[1] = _inv_bin[2] ^ _inv_bin[1];
    gray[0] = _inv_bin[1] ^ _inv_bin[0];
end

endmodule
